Bash(source .env.local 2>/dev/null; export GEMINI_API_KEY; curl -s "https://generativelanguage.googleapis.com/v1beta/models/veo-3.0-fast-generate-001/operations/yx5s2qwpyyzv?key=$GEMINI_API_KEY" 2>&1 | node -e "
const d=require\('fs'\).readFileSync\(0,'utf8'\);
const j=JSON.parse\(d\);
console.log\('done:', j.done\);
console.log\('response type:', j.response?.['@type']\);
const keys = Object.keys\(j.response || {}\);
console.log\('response keys:', keys\);
// Show structure without huge base64 data
const r = j.response;
if \(r?.generateVideoResponse\) {
  const gvr = r.generateVideoResponse;
  console.log\('generateVideoResponse keys:', Object.keys\(gvr\)\);
  if \(gvr.generatedSamples\) {
    console.log\('samples count:', gvr.generatedSamples.length\);
    const s = gvr.generatedSamples[0];
    if \(s.video\) console.log\('video keys:', Object.keys\(s.video\), 'uri length:', s.video.uri?.length, 'encoding:', s.video.encoding\);
  }
}
// Check for other patterns
for \(const k of keys\) {
  if \(k !== '@type'\) {
    const v = r[k];
    if \(typeof v === 'string' && v.length > 100\) console.log\(k, ': string len', v.length\);
    else if \(Array.isArray\(v\)\) {
      console.log\(k, ': array len', v.length\);
      if \(v[0]\) console.log\('  [0] keys:', Object.keys\(v[0]\)\);
    }
    else console.log\(k, ':', JSON.stringify\(v\)?.slice\(0,200\)\);
  }
}
")

Bash(source .env.local 2>/dev/null; export GEMINI_API_KEY; curl -s "https://generativelanguage.googleapis.com/v1beta/models/veo-3.0-fast-generate-001/operations/yx5s2qwpyyzv?key=$GEMINI_API_KEY" 2>&1 | node -e "
const d=require\('fs'\).readFileSync\(0,'utf8'\);
const j=JSON.parse\(d\);
// Remove large base64 values for display
function summarize\(obj, depth\) {
  if \(depth > 4\) return '...';
  if \(typeof obj === 'string' && obj.length > 200\) return '[string:' + obj.length + 'chars]';
  if \(Array.isArray\(obj\)\) return obj.map\(x => summarize\(x, depth+1\)\);
  if \(obj && typeof obj === 'object'\) {
    const r = {};
    for \(const [k,v] of Object.entries\(obj\)\) r[k] = summarize\(v, depth+1\);
    return r;
  }
  return obj;
}
console.log\(JSON.stringify\(summarize\(j, 0\), null, 2\)\);
")

